"""Tech catalog (mirror of apworld/stellaris/data/tech_catalog.py).

This file is read by the runtime client (ap_bridge.py + slot_generator.py)
which lives in a separate distribution from the apworld. The two files MUST
stay byte-for-byte identical aside from this header — the offsets, item
IDs, and location IDs are derived from this data and a divergence between
client and apworld would silently corrupt seeds.

Sync command:
    cp apworld/stellaris/data/tech_catalog.py client/tech_catalog.py
"""

from typing import Dict, List, NamedTuple, Optional


class TechCatalogEntry(NamedTuple):
    key: str            # Stellaris tech key (e.g. "tech_synthetic_workers")
    display: str        # Human-readable name (e.g. "Synthetics")
    tier: int           # Stellaris tech tier (0-5)
    area: str           # "physics" | "society" | "engineering"
    prereqs: List[str]  # Vanilla tech prerequisites
    dlc: Optional[str]  # DLC short flag, or None for base game
    offset: int         # Stable ID offset — NEVER change after release
    category: str       # Stellaris tech category (e.g. "biology")
    is_rare: bool       # Whether the vanilla tech is rare
    is_dangerous: bool  # Whether researching it triggers a dangerous event


