# Default selection is empty: the player picks which techs to randomize
# via the Tech Config dashboard tab. The apworld accepts an empty set.
_DEFAULT_KEYS: List[str] = [
]


def by_key() -> Dict[str, TechCatalogEntry]:
    """Lookup table from tech key to catalog entry."""
    return {t.key: t for t in TECH_CATALOG}


def all_keys() -> List[str]:
    """All tech keys in the catalog, in offset order."""
    return [t.key for t in TECH_CATALOG]


def default_selection() -> List[str]:
    """Tech keys randomized when the player does not customize.

    Empty by default; the dashboard's Tech Config tab is the path
    to populate this. Returning an empty list keeps the seed lean
    until the player explicitly chooses what to randomize.
    """
    return list(_DEFAULT_KEYS)


def location_name(entry: TechCatalogEntry) -> str:
    """The AP location name shown to players."""
    return f"Research {entry.display}"


def item_name(entry: TechCatalogEntry) -> str:
    """The AP item name carried in the multiworld."""
    return f"Tech: {entry.display}"


def _validate():
    """Sanity-check the catalog at module load."""
    seen_keys = set()
    seen_offsets = set()
    for t in TECH_CATALOG:
        if t.key in seen_keys:
            raise ValueError(f"Tech catalog: duplicate key {t.key!r}")
        if t.offset in seen_offsets:
            raise ValueError(f"Tech catalog: duplicate offset {t.offset} on {t.key!r}")
        if t.area not in {"physics", "society", "engineering"}:
            raise ValueError(f"Tech catalog: invalid area {t.area!r} on {t.key!r}")
        if t.tier < 0 or t.tier > 5:
            raise ValueError(f"Tech catalog: tier {t.tier} out of range on {t.key!r}")
        seen_keys.add(t.key)
        seen_offsets.add(t.offset)


_validate()
